"use client"

import useSWR from "swr"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Skeleton } from "@/components/ui/skeleton"
import { CheckCircle2, Clock } from "lucide-react"

interface Vote {
  id: string
  electionId: string
  electionTitle: string
  partyId: string
  partyName: string
  timestamp: Date
  blockchainHash: string
}

export function UserVotingHistory() {
  const { data, isLoading } = useSWR("/api/user/voting-history", async (url) => {
    const response = await fetch(url)
    return response.json()
  })

  const votes: Vote[] = data?.votes || []

  return (
    <Card>
      <CardHeader>
        <CardTitle>Your Voting History</CardTitle>
        <CardDescription>All your votes are permanently recorded on blockchain</CardDescription>
      </CardHeader>
      <CardContent>
        {isLoading ? (
          <div className="space-y-3">
            {[1, 2, 3].map((i) => (
              <Skeleton key={i} className="h-20" />
            ))}
          </div>
        ) : votes.length === 0 ? (
          <p className="text-gray-500 py-8 text-center">No voting history yet</p>
        ) : (
          <div className="space-y-3">
            {votes.map((vote) => (
              <div key={vote.id} className="border rounded-lg p-4 space-y-2">
                <div className="flex items-center justify-between">
                  <h3 className="font-semibold">{vote.electionTitle}</h3>
                  <Badge variant="secondary">
                    <CheckCircle2 className="w-3 h-3 mr-1" />
                    Voted
                  </Badge>
                </div>
                <p className="text-sm text-gray-600">Voted for: {vote.partyName}</p>
                <div className="flex items-center gap-2 text-xs text-gray-500">
                  <Clock className="w-3 h-3" />
                  {new Date(vote.timestamp).toLocaleDateString()}
                </div>
                <p className="text-xs font-mono bg-gray-100 p-2 rounded break-all text-gray-600">
                  Blockchain: {vote.blockchainHash}
                </p>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  )
}
